import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.BKG_UbFK.js";const g=JSON.parse('{"title":"النشر (Publishing)","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/publishing.md","filePath":"ar/guide/publishing.md"}'),t={name:"ar/guide/publishing.md"};function n(o,a,h,c,d,r){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="النشر-publishing" tabindex="-1">النشر (Publishing) <a class="header-anchor" href="#النشر-publishing" aria-label="Permalink to &quot;النشر (Publishing)&quot;">​</a></h1><p>تنشر Clearance ثلاثة أنواع من الأصول عبر وسوم <code>vendor:publish</code>: الإعداد، والترحيلات (migrations)، والترجمات. تُدار الإعدادات والترحيلات تلقائياً بواسطة أداة التثبيت (انظر <a href="/clearance-docs/ar/guide/installation.html">التثبيت</a>)؛ تغطي هذه الصفحة نشرها يدوياً، ونشر الترجمات.</p><h2 id="الإعداد" tabindex="-1">الإعداد <a class="header-anchor" href="#الإعداد" aria-label="Permalink to &quot;الإعداد&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>ينشر <code>config/clearance.php</code> إلى تطبيقك. انظر <a href="/clearance-docs/ar/guide/configuration.html">مرجع الإعدادات</a> للاطلاع على كل مفتاح، وقيمته الافتراضية، وغرضه.</p><h2 id="الترجمات" tabindex="-1">الترجمات <a class="header-anchor" href="#الترجمات" aria-label="Permalink to &quot;الترجمات&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>هذا ينسخ اللغات التسع المرفقة (<code>ar</code>، <code>en</code>، <code>es</code>، <code>fr</code>، <code>hi</code>، <code>it</code>، <code>pt</code>، <code>ru</code>، <code>zh</code>) إلى <code>lang/vendor/clearance/{locale}/ui.php</code> في تطبيقك. لإضافة لغة جديدة أو لتجاوز نصوص في لغة موجودة، أضف مجلد لغة هناك، مستخدماً <code>en/ui.php</code> كمرجع أساسي للمفاتيح. تعرض جميع اللغات مجموعة مفاتيح متطابقة، يتم التحقق منها باختبار مخصص عند كل تغيير.</p><h2 id="تجاوز-تخطيط-اللوحة" tabindex="-1">تجاوز تخطيط اللوحة <a class="header-anchor" href="#تجاوز-تخطيط-اللوحة" aria-label="Permalink to &quot;تجاوز تخطيط اللوحة&quot;">​</a></h2><p>يتحكم مفتاح الإعداد <code>layout</code> في تخطيط Blade المستخدم للمكوّنات ذات الصفحة الكاملة:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>اتركه <code>null</code> لاستخدام تخطيط Livewire الافتراضي لتطبيقك، أو عيّنه إلى عرض تخطيط محدد لعرض اللوحة داخل غلاف (shell) مخصص.</p><h2 id="الترحيلات-migrations" tabindex="-1">الترحيلات (Migrations) <a class="header-anchor" href="#الترحيلات-migrations" aria-label="Permalink to &quot;الترحيلات (Migrations)&quot;">​</a></h2><p>تُنشر ترحيلات Clearance وتُشغَّل تلقائياً بواسطة <code>php artisan clearance:install</code> - كما تنشر أداة التثبيت وتُشغّل ترحيلات Spatie أولاً إذا لم يكن جدول <code>roles</code> موجوداً بعد. انظر <a href="/clearance-docs/ar/guide/installation.html">التثبيت</a> للاطلاع على تدفق خطوة بخطوة الكامل، و<a href="/clearance-docs/ar/guide/installation.html#run-the-installer">تنبيه الخطر</a> حول عدم تشغيل <code>migrate</code> مباشرة أبداً على إعداد جديد.</p><h2 id="ذو-صلة" tabindex="-1">ذو صلة <a class="header-anchor" href="#ذو-صلة" aria-label="Permalink to &quot;ذو صلة&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/guide/configuration.html">مرجع الإعدادات</a> - كل مفتاح إعداد</li><li><a href="/clearance-docs/ar/guide/installation.html">التثبيت</a> - تدفق أداة التثبيت الكامل</li><li><a href="/clearance-docs/ar/guide/migration.html">الترحيل</a> - <code>clearance:backfill</code> لتثبيتات Spatie الموجودة مسبقاً</li></ul>`,16)])])}const u=e(t,[["render",n]]);export{g as __pageData,u as default};
